custom_css:
/* ==========================================================
   名称：神秘紫色魔法主题
   样式作者：AI Generated
   版本：v1.0
   基于：复古MacOS UI主题
   ========================================================== */

@import url("https://fontsapi.zeoseven.com/570/main/result.css");

body {
    font-family: "Fusion Pixel 12px Monospaced zh_hans";
    font-weight: normal;
    background: linear-gradient(135deg, #1a0a35 0%, #2d154e 50%, #1a0a35 100%);
}

code, textarea, #send_textarea, input, select, button, .text_pole, .font-family-reset {
  font-family: inherit;
}

:root {
    --mainFontSize: calc(var(--fontScale)* 16px);
    --avatar-base-width: 48px;
    --avatar-base-height: 48px;
    --topbarIconSize: calc(var(--mainFontSize)* 1.3);
    --genericRadius: 8px;
    --warning: #ff6b6b;
    --crimson70a: rgba(230, 180, 255, 0.4);
    --crimson-hover: color-mix(in srgb, var(--SmartThemeUnderlineColor), transparent 85%) !important;
    --standardIconSize: calc(var(--mainFontSize)* 1);
    --bottomFormIconSize: calc(var(--mainFontSize)* 1.5);
    --bottomFormBlockPadding: calc(var(--mainFontSize) / 1.5);
    --scrollBarWidth: 4px;
    --pagePadding: calc(var(--scrollBarWidth) + 9px);
    --genericLineHeight: calc(var(--mainFontSize)* 1.8);

    --utilityColor: rgba(230, 180, 255, 0.7);
    --navBackgroundColor: rgba(30, 15, 60, 0.95);
    --buttonFill: rgba(60, 30, 100, 0.8);
    --menuBackgroundColor: rgba(40, 20, 80, 0.95);
    --accentColor: rgba(255, 215, 100, 1);
    --accentColorOverlay: color-mix(in srgb, var(--SmartThemeBorderColor), transparent 85%);
    --scrollBarColor: rgba(180, 140, 220, 0.8);
    --boxShadowSubtle: 0 0 15px rgba(180, 140, 220, 0.3);
    --boxShadowSubtleAlt: 0 0 20px rgba(100, 50, 150, 0.4);
    --boxShadowMedium: 0 0 25px rgba(180, 140, 220, 0.4);
    --boxShadowHover: 0 0 30px rgba(255, 215, 100, 0.3);
    --boxShadowDropdown: 0 8px 32px rgba(0, 0, 0, 0.5);
    --boxShadowPopup: 0 0 40px rgba(180, 140, 220, 0.5);
    --buttonHoverGlow: 0 0 20px rgba(255, 215, 100, 0.4);
    --buttonActiveGlow: 0 0 10px rgba(255, 215, 100, 0.6);
    --borderColor: rgba(180, 140, 220, 0.6);
    --borderColorLight: rgba(200, 160, 240, 0.4);
    --borderColorDark: rgba(100, 50, 150, 0.6);
    --buttonBorderRadius: 6px;
    --inputBorderRadius: 8px;
    --panelBorderRadius: 12px;
    --chatItemBorderRadius: 12px;
    --tooltipBorderRadius: 6px;
    --dropdownBorderRadius: 8px;
    --hoverTransitionDuration: 0.3s;
    --hoverTransitionEase: cubic-bezier(0.4, 0, 0.2, 1);
    --backgroundColorPrimary: rgba(20, 10, 40, 0.9);
    --backgroundColorSecondary: rgba(30, 15, 60, 0.95);
    --backgroundColorTertiary: rgba(40, 20, 80, 0.9);
    --backgroundColorHover: rgba(60, 30, 100, 0.8);
    --textColorPrimary: rgba(255, 215, 100, 1);
    --textColorSecondary: rgba(230, 180, 255, 0.9);
    --textColorTertiary: rgba(200, 160, 240, 0.7);
    --textColorMuted: rgba(160, 120, 200, 0.5);
    --textColorInverse: rgba(20, 10, 40, 1);
    --successColor: rgba(100, 220, 150, 0.8);
    --warningColor: rgba(255, 180, 100, 0.8);
    --errorColor: rgba(255, 100, 150, 0.8);
    --infoColor: rgba(100, 180, 255, 0.8);
    --gradientGold: linear-gradient(135deg, #ffd700 0%, #ffb700 50%, #ffd700 100%);
    --gradientPurple: linear-gradient(135deg, #6b21a8 0%, #4c1d95 100%);
    --gradientDark: linear-gradient(180deg, rgba(30, 15, 60, 0.95) 0%, rgba(20, 10, 40, 0.98) 100%);
}

::-webkit-scrollbar {
    width: var(--scrollBarWidth);
    height: var(--scrollBarWidth);
}

::-webkit-scrollbar-track {
    background: rgba(20, 10, 40, 0.5);
    border-radius: var(--scrollBarWidth);
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, rgba(180, 140, 220, 0.8), rgba(140, 100, 180, 0.6));
    border-radius: var(--scrollBarWidth);
}

::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, rgba(200, 160, 240, 0.9), rgba(160, 120, 200, 0.7));
}

#chat_box {
    background: transparent;
}

.message-row {
    margin-bottom: 12px;
}

.message-row .message-box {
    background: linear-gradient(135deg, rgba(40, 20, 80, 0.8), rgba(30, 15, 60, 0.9));
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--chatItemBorderRadius);
    box-shadow: var(--boxShadowSubtle);
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

.message-row .message-box:hover {
    border-color: rgba(255, 215, 100, 0.6);
    box-shadow: var(--boxShadowHover);
}

.message-row.user .message-box {
    background: linear-gradient(135deg, rgba(50, 25, 100, 0.75), rgba(40, 20, 80, 0.85));
}

.message-content {
    color: var(--textColorSecondary);
    line-height: var(--genericLineHeight);
}

.message-content p {
    margin: 8px 0;
}

.message-content em {
    color: var(--textColorTertiary);
    font-style: italic;
}

.message-content strong {
    color: var(--textColorPrimary);
    font-weight: 600;
}

.message-content u {
    color: var(--underline_text_color);
    text-decoration: underline;
    text-decoration-color: rgba(180, 140, 220, 0.6);
}

.message-content blockquote {
    border-left: 3px solid rgba(255, 215, 100, 0.6);
    background: rgba(30, 15, 60, 0.6);
    padding: 8px 16px;
    margin: 8px 0;
    border-radius: 0 6px 6px 0;
    color: var(--quote_text_color);
    font-style: italic;
}

.message-content code {
    background: rgba(100, 50, 150, 0.6);
    padding: 2px 6px;
    border-radius: 4px;
    font-size: 0.9em;
    color: var(--textColorTertiary);
}

.message-content pre {
    background: rgba(20, 10, 40, 0.9);
    border: 1px solid rgba(180, 140, 220, 0.3);
    border-radius: 8px;
    padding: 12px;
    overflow-x: auto;
}

.message-content pre code {
    background: transparent;
    padding: 0;
}

.name-role-row {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 6px;
}

.name-role-row .user-name {
    color: var(--textColorPrimary);
    font-weight: 600;
    text-shadow: 0 0 10px rgba(255, 215, 100, 0.3);
}

.name-role-row .role-badge {
    background: rgba(180, 140, 220, 0.3);
    border: 1px solid rgba(200, 160, 240, 0.4);
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.75em;
    color: var(--textColorTertiary);
}

#send_textarea {
    background: linear-gradient(135deg, rgba(30, 15, 60, 0.9), rgba(20, 10, 40, 0.95));
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--inputBorderRadius);
    color: var(--textColorSecondary);
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

#send_textarea:focus {
    border-color: rgba(255, 215, 100, 0.6);
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.2);
    outline: none;
}

#send_textarea::placeholder {
    color: var(--textColorMuted);
}

button {
    background: linear-gradient(135deg, rgba(60, 30, 100, 0.8), rgba(50, 25, 80, 0.9));
    border: 1px solid rgba(180, 140, 220, 0.5);
    border-radius: var(--buttonBorderRadius);
    color: var(--textColorSecondary);
    padding: 8px 16px;
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

button:hover {
    background: linear-gradient(135deg, rgba(80, 40, 120, 0.9), rgba(60, 30, 100, 0.95));
    border-color: rgba(255, 215, 100, 0.6);
    box-shadow: var(--buttonHoverGlow);
}

button:active {
    box-shadow: var(--buttonActiveGlow);
    transform: scale(0.98);
}

button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.top-bar {
    background: var(--gradientDark);
    border-bottom: 1px solid rgba(180, 140, 220, 0.3);
}

.top-bar .icon {
    color: var(--textColorSecondary);
    transition: color var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

.top-bar .icon:hover {
    color: var(--textColorPrimary);
}

.sidebar {
    background: rgba(20, 10, 40, 0.95);
    border-right: 1px solid rgba(180, 140, 220, 0.2);
}

.chat-item {
    padding: 10px 12px;
    border-radius: var(--chatItemBorderRadius);
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

.chat-item:hover {
    background: rgba(60, 30, 100, 0.5);
}

.chat-item.active {
    background: rgba(180, 140, 220, 0.2);
    border-left: 3px solid rgba(255, 215, 100, 0.6);
}

.chat-item-title {
    color: var(--textColorSecondary);
}

.chat-item-subtitle {
    color: var(--textColorMuted);
    font-size: 0.85em;
}

.modal-content {
    background: linear-gradient(135deg, rgba(30, 15, 60, 0.98), rgba(20, 10, 40, 0.99));
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--panelBorderRadius);
    box-shadow: var(--boxShadowPopup);
}

.modal-header {
    border-bottom: 1px solid rgba(180, 140, 220, 0.2);
    color: var(--textColorPrimary);
}

.modal-footer {
    border-top: 1px solid rgba(180, 140, 220, 0.2);
}

.dropdown-menu {
    background: rgba(40, 20, 80, 0.98);
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--dropdownBorderRadius);
    box-shadow: var(--boxShadowDropdown);
}

.dropdown-item {
    color: var(--textColorSecondary);
    padding: 8px 16px;
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

.dropdown-item:hover {
    background: rgba(180, 140, 220, 0.2);
    color: var(--textColorPrimary);
}

.toast {
    background: linear-gradient(135deg, rgba(40, 20, 80, 0.95), rgba(30, 15, 60, 0.98));
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--tooltipBorderRadius);
    color: var(--textColorSecondary);
    box-shadow: var(--boxShadowMedium);
}

.toast-success {
    border-color: rgba(100, 220, 150, 0.6);
}

.toast-error {
    border-color: rgba(255, 100, 150, 0.6);
}

.toast-warning {
    border-color: rgba(255, 180, 100, 0.6);
}

.tag {
    background: rgba(180, 140, 220, 0.2);
    border: 1px solid rgba(200, 160, 240, 0.3);
    border-radius: 4px;
    padding: 2px 8px;
    color: var(--textColorTertiary);
    font-size: 0.85em;
}

.badge {
    background: rgba(255, 100, 150, 0.8);
    border-radius: 50%;
    color: white;
    font-size: 0.75em;
    padding: 2px 6px;
    min-width: 18px;
    text-align: center;
}

.progress-bar {
    background: rgba(20, 10, 40, 0.8);
    border-radius: 4px;
    overflow: hidden;
}

.progress-bar-fill {
    background: linear-gradient(90deg, rgba(180, 140, 220, 0.8), rgba(255, 215, 100, 0.8));
    transition: width 0.3s ease;
}

input[type="text"], input[type="password"], input[type="email"], select {
    background: rgba(30, 15, 60, 0.9);
    border: 1px solid rgba(180, 140, 220, 0.4);
    border-radius: var(--inputBorderRadius);
    color: var(--textColorSecondary);
    padding: 8px 12px;
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
}

input:focus, select:focus {
    border-color: rgba(255, 215, 100, 0.6);
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.2);
    outline: none;
}

.divider {
    border-top: 1px solid rgba(180, 140, 220, 0.2);
    margin: 16px 0;
}

.card {
    background: linear-gradient(135deg, rgba(30, 15, 60, 0.9), rgba(20, 10, 40, 0.95));
    border: 1px solid rgba(180, 140, 220, 0.3);
    border-radius: var(--panelBorderRadius);
    box-shadow: var(--boxShadowSubtle);
}

.card-header {
    border-bottom: 1px solid rgba(180, 140, 220, 0.2);
    color: var(--textColorPrimary);
    padding: 12px 16px;
}

.card-body {
    padding: 16px;
}

.card-footer {
    border-top: 1px solid rgba(180, 140, 220, 0.2);
    padding: 12px 16px;
}

@keyframes twinkle {
    0%, 100% { opacity: 0.3; }
    50% { opacity: 1; }
}

@keyframes glow {
    0%, 100% { box-shadow: 0 0 5px rgba(255, 215, 100, 0.3); }
    50% { box-shadow: 0 0 20px rgba(255, 215, 100, 0.6); }
}

.animate-twinkle {
    animation: twinkle 2s ease-in-out infinite;
}

.animate-glow {
    animation: glow 2s ease-in-out infinite;
}

.star-decoration {
    position: absolute;
    width: 4px;
    height: 4px;
    background: rgba(255, 215, 100, 0.8);
    border-radius: 50%;
    animation: twinkle 3s ease-in-out infinite;
}

.moon-icon {
    color: var(--textColorPrimary);
    text-shadow: 0 0 10px rgba(255, 215, 100, 0.5);
}

.spell-button {
    background: linear-gradient(135deg, rgba(80, 40, 120, 0.9), rgba(60, 30, 100, 0.95));
    border: 2px solid rgba(255, 215, 100, 0.4);
    border-radius: 50%;
    width: 50px;
    height: 50px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--textColorPrimary);
    font-size: 1.2em;
    transition: all var(--hoverTransitionDuration) var(--hoverTransitionEase);
    box-shadow: 0 0 15px rgba(255, 215, 100, 0.2);
}

.spell-button:hover {
    border-color: rgba(255, 215, 100, 0.8);
    box-shadow: 0 0 25px rgba(255, 215, 100, 0.4);
    transform: scale(1.05);
}

.arcane-title {
    font-size: 1.5em;
    color: var(--textColorPrimary);
    text-shadow: 0 0 20px rgba(255, 215, 100, 0.4);
    letter-spacing: 2px;
}

.grimoire-footer {
    text-align: center;
    color: var(--textColorMuted);
    font-size: 0.8em;
    padding: 16px;
    border-top: 1px solid rgba(180, 140, 220, 0.1);
}

.mana-cost {
    background: rgba(180, 140, 220, 0.2);
    border: 1px solid rgba(200, 160, 240, 0.3);
    border-radius: 20px;
    padding: 6px 12px;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    color: var(--textColorTertiary);
    font-size: 0.9em;
}

.mana-cost .icon {
    color: rgba(255, 215, 100, 0.8);
}

.scroll-container {
    background: linear-gradient(135deg, rgba(40, 20, 80, 0.6), rgba(30, 15, 60, 0.8));
    border: 1px solid rgba(180, 140, 220, 0.3);
    border-radius: var(--panelBorderRadius);
    padding: 20px;
    position: relative;
}

.scroll-container::before {
    content: '"';
    position: absolute;
    top: -10px;
    left: 50%;
    transform: translateX(-50%);
    font-size: 3em;
    color: rgba(255, 215, 100, 0.3);
    font-family: serif;
}

.scroll-content {
    color: var(--textColorSecondary);
    font-style: italic;
    text-align: center;
    line-height: 1.8;
}
